// Generated by claude-sf-toolkit. Customize for your project.
#!/usr/bin/env node
"use strict";

/**
 * backlog-validate.js — Validate backlog.yaml and archive.yaml structure and references
 *
 * Usage:
 *   node scripts/backlog-validate.js [options]
 *
 * Options:
 *   --backlog-path <path>   Path to backlog.yaml (default: docs/backlog/backlog.yaml)
 *   --archive-path <path>   Path to archive.yaml (default: docs/backlog/archive.yaml)
 *   --tags-path <path>      Path to tags.yaml (default: docs/backlog/tags.yaml)
 *   --fix                   Auto-fix missing updated dates
 *   --help                  Show this help message
 *
 * Exit codes: 0 = valid, 1 = validation errors found
 */

const fs = require("fs");
const path = require("path");
const yaml = require("js-yaml");

const REPO_ROOT = path.join(__dirname, "..");

// ---------------------------------------------------------------------------
// Argument parsing
// ---------------------------------------------------------------------------

function parseCliArgs(argv) {
  const args = {};
  let i = 2;
  while (i < argv.length) {
    const key = argv[i];
    if (key === "--help") {
      console.log(
        [
          "Usage: node scripts/backlog-validate.js [options]",
          "",
          "Options:",
          "  --backlog-path <path>   Path to backlog.yaml (default: docs/backlog/backlog.yaml)",
          "  --archive-path <path>   Path to archive.yaml (default: docs/backlog/archive.yaml)",
          "  --tags-path <path>      Path to tags.yaml (default: docs/backlog/tags.yaml)",
          "  --fix                   Auto-fix missing updated dates",
          "  --help                  Show this help message"
        ].join("\n")
      );
      process.exit(0);
    }
    if (key === "--fix") {
      args.fix = true;
      i++;
    } else if (key.startsWith("--")) {
      const name = key.slice(2);
      if (i + 1 >= argv.length) {
        console.error(`Error: --${name} requires a value`);
        process.exit(1);
      }
      args[name] = argv[i + 1];
      i += 2;
    } else {
      // Positional arg treated as backlog path
      args["backlog-path"] = argv[i];
      i++;
    }
  }
  return args;
}

const CLI_ARGS = parseCliArgs(process.argv);
const doFix = CLI_ARGS.fix || false;

const BACKLOG_FILE = path.resolve(
  REPO_ROOT,
  CLI_ARGS["backlog-path"] || "docs/backlog/backlog.yaml"
);
const ARCHIVE_FILE = path.resolve(
  REPO_ROOT,
  CLI_ARGS["archive-path"] || "docs/backlog/archive.yaml"
);
const TAGS_FILE = path.resolve(
  REPO_ROOT,
  CLI_ARGS["tags-path"] || "docs/backlog/tags.yaml"
);

const VALID_CATEGORIES = ["Platform", "Integrations", "Portal", "Operations"];
const VALID_STATUSES = [
  "Captured",
  "Evaluated",
  "Prioritized",
  "Ready",
  "In Progress",
  "Done",
  "Deferred"
];
const VALID_PRIORITIES = ["P1", "P2", "P3", "P4", "Unset"];
const VALID_EFFORTS = ["S", "M", "L", "XL", "Unset"];
const VALID_COMPLEXITIES = ["Low", "Med", "High", "Unset"];
const VALID_CBC_SCORES = [1, 2, 3, 4, 5];
const VALID_SOURCES = [
  "team-member",
  "stakeholder-request",
  "vendor-eval",
  "claude-session"
];

const REQUIRED_FIELDS = [
  "id",
  "title",
  "description",
  "category",
  "status",
  "priority",
  "effort",
  "complexity",
  "tags",
  "source",
  "submitted_by",
  "assigned_to",
  "target_date",
  "design_doc",
  "devops_wis",
  "blocked_by",
  "related",
  "created",
  "updated",
  "notes"
];

const errors = [];
const warnings = [];

function error(file, itemId, message) {
  errors.push(`ERROR: ${file}: ${itemId}: ${message}`);
}

function warn(message) {
  warnings.push(`WARN: ${message}`);
}

function isValidDate(str) {
  if (typeof str !== "string") return false;
  if (!/^\d{4}-\d{2}-\d{2}$/.test(str)) return false;
  const d = new Date(str + "T00:00:00Z");
  return !isNaN(d.getTime());
}

function today() {
  return new Date().toISOString().slice(0, 10);
}

// Parse files
let backlogData, archiveData, tagsData;
let backlogRaw, archiveRaw;
let backlogModified = false;

try {
  backlogRaw = fs.readFileSync(BACKLOG_FILE, "utf8");
  backlogData = yaml.load(backlogRaw);
} catch (e) {
  console.error(`ERROR: ${path.basename(BACKLOG_FILE)}: Failed to parse YAML: ${e.message}`);
  process.exit(1);
}

let archiveExists = fs.existsSync(ARCHIVE_FILE);
if (archiveExists) {
  try {
    archiveRaw = fs.readFileSync(ARCHIVE_FILE, "utf8");
    archiveData = yaml.load(archiveRaw);
  } catch (e) {
    console.error(`ERROR: ${path.basename(ARCHIVE_FILE)}: Failed to parse YAML: ${e.message}`);
    process.exit(1);
  }
}

try {
  tagsData = yaml.load(fs.readFileSync(TAGS_FILE, "utf8"));
} catch (e) {
  console.error(`ERROR: ${path.basename(TAGS_FILE)}: Failed to parse YAML: ${e.message}`);
  process.exit(1);
}

const validTags = new Set(tagsData.tags || []);
const backlogItems = (backlogData && backlogData.items) || [];
const archiveItems = (archiveData && archiveData.items) || [];

// Collect all IDs for cross-reference checks
const allIds = new Set();
const idToFile = {};

function registerIds(items, fileName) {
  for (const item of items) {
    if (!item || !item.id) continue;
    if (allIds.has(item.id)) {
      error(fileName, item.id, `Duplicate ID (also in ${idToFile[item.id]})`);
    } else {
      allIds.add(item.id);
      idToFile[item.id] = fileName;
    }
  }
}

registerIds(backlogItems, path.basename(BACKLOG_FILE));
registerIds(archiveItems, path.basename(ARCHIVE_FILE));

function validateItem(item, fileName, idPattern) {
  if (!item || typeof item !== "object") {
    error(fileName, "???", "Item is not an object");
    return;
  }

  const id = item.id || "???";

  // Required fields
  for (const field of REQUIRED_FIELDS) {
    if (!(field in item)) {
      error(fileName, id, `Missing required field: ${field}`);
    }
  }

  // ID format
  if (item.id && !idPattern.test(item.id)) {
    error(fileName, id, `ID does not match expected format ${idPattern}`);
  }

  // Enum validations
  if (item.category && !VALID_CATEGORIES.includes(item.category)) {
    error(
      fileName,
      id,
      `Invalid category: ${item.category}. Must be one of: ${VALID_CATEGORIES.join(", ")}`
    );
  }
  if (item.status && !VALID_STATUSES.includes(item.status)) {
    error(
      fileName,
      id,
      `Invalid status: ${item.status}. Must be one of: ${VALID_STATUSES.join(", ")}`
    );
  }
  if (item.priority && !VALID_PRIORITIES.includes(item.priority)) {
    error(
      fileName,
      id,
      `Invalid priority: ${item.priority}. Must be one of: ${VALID_PRIORITIES.join(", ")}`
    );
  }
  if (item.effort && !VALID_EFFORTS.includes(item.effort)) {
    error(
      fileName,
      id,
      `Invalid effort: ${item.effort}. Must be one of: ${VALID_EFFORTS.join(", ")}`
    );
  }
  if (item.complexity && !VALID_COMPLEXITIES.includes(item.complexity)) {
    error(
      fileName,
      id,
      `Invalid complexity: ${item.complexity}. Must be one of: ${VALID_COMPLEXITIES.join(", ")}`
    );
  }
  if (item.cbc_score != null && !VALID_CBC_SCORES.includes(item.cbc_score)) {
    error(
      fileName,
      id,
      `Invalid cbc_score: ${item.cbc_score}. Must be one of: ${VALID_CBC_SCORES.join(", ")} or null`
    );
  }
  if (item.source && !VALID_SOURCES.includes(item.source)) {
    error(
      fileName,
      id,
      `Invalid source: ${item.source}. Must be one of: ${VALID_SOURCES.join(", ")}`
    );
  }

  // Tags validation
  if (Array.isArray(item.tags)) {
    for (const tag of item.tags) {
      if (!validTags.has(tag)) {
        error(fileName, id, `Unknown tag: ${tag}. Not found in tags.yaml`);
      }
    }
  }

  // blocked_by and related references
  if (Array.isArray(item.blocked_by)) {
    for (const ref of item.blocked_by) {
      if (!allIds.has(ref)) {
        error(fileName, id, `blocked_by references unknown ID: ${ref}`);
      }
    }
  }
  if (Array.isArray(item.related)) {
    for (const ref of item.related) {
      if (!allIds.has(ref)) {
        error(fileName, id, `related references unknown ID: ${ref}`);
      }
    }
  }

  // devops_wis format
  if (Array.isArray(item.devops_wis)) {
    for (const wi of item.devops_wis) {
      if (!/^WI-\d{6}$/.test(wi)) {
        error(
          fileName,
          id,
          `Invalid devops_wis format: ${wi}. Expected WI-NNNNNN`
        );
      }
    }
  }

  // design_doc path check
  if (item.design_doc != null && item.design_doc !== "") {
    const docPath = path.join(REPO_ROOT, item.design_doc);
    if (!fs.existsSync(docPath)) {
      error(fileName, id, `design_doc path does not exist: ${item.design_doc}`);
    }
  }

  // Date validation
  if ("created" in item) {
    const created = String(item.created);
    if (!isValidDate(created)) {
      error(
        fileName,
        id,
        `Invalid created date: ${item.created}. Expected YYYY-MM-DD`
      );
    }
  }

  if ("updated" in item) {
    const updated = item.updated;
    if (updated == null || updated === "") {
      if (doFix) {
        item.updated = today();
        warn(
          `${fileName}: ${id}: Auto-fixed missing updated date to ${today()}`
        );
        if (fileName === path.basename(BACKLOG_FILE)) backlogModified = true;
      } else {
        error(fileName, id, "Missing updated date");
      }
    } else if (!isValidDate(String(updated))) {
      error(
        fileName,
        id,
        `Invalid updated date: ${updated}. Expected YYYY-MM-DD`
      );
    }
  }

  // Notes validation
  if (Array.isArray(item.notes)) {
    for (let i = 0; i < item.notes.length; i++) {
      const note = item.notes[i];
      if (note == null) continue;
      if (typeof note === "string") {
        // Legacy string notes — warn but don't error
        warn(
          `${fileName}: ${id}: notes[${i}] is a plain string, expected object with date/author/text`
        );
        continue;
      }
      if (typeof note === "object") {
        if (!note.date) error(fileName, id, `notes[${i}] missing 'date' field`);
        if (!note.author)
          error(fileName, id, `notes[${i}] missing 'author' field`);
        if (!note.text) error(fileName, id, `notes[${i}] missing 'text' field`);
      }
    }
  }
}

// Validate backlog items
for (const item of backlogItems) {
  validateItem(item, path.basename(BACKLOG_FILE), /^BL-\d{4}$/);
}

// Validate archive items
for (const item of archiveItems) {
  validateItem(item, path.basename(ARCHIVE_FILE), /^BL-A\d{3,4}$/);
}

// next_id check
if (backlogData && backlogData.next_id != null) {
  let maxNum = 0;
  for (const item of backlogItems) {
    if (!item || !item.id) continue;
    const match = item.id.match(/^BL-(\d{4})$/);
    if (match) {
      const num = parseInt(match[1], 10);
      if (num > maxNum) maxNum = num;
    }
  }
  if (backlogData.next_id <= maxNum) {
    error(
      path.basename(BACKLOG_FILE),
      "next_id",
      `next_id (${backlogData.next_id}) must be greater than highest BL-NNNN number (${maxNum})`
    );
  }
}

// Write fixes if needed
if (doFix && backlogModified) {
  const output = yaml.dump(backlogData, {
    lineWidth: 120,
    noRefs: true,
    quotingType: '"'
  });
  fs.writeFileSync(BACKLOG_FILE, output, "utf8");
  warn(`${path.basename(BACKLOG_FILE)} was updated with auto-fixes`);
}

// Output
for (const e of errors) console.log(e);
for (const w of warnings) console.log(w);
console.log(
  `\nValidation complete — ${errors.length} errors, ${warnings.length} warnings.`
);

process.exit(errors.length > 0 ? 1 : 0);
